use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    Assigned,
    InProgress,
    Closed,
}

enum Event<'a> {
    Create(&'a str),
    Assign(&'a str, &'a str),
    Start(&'a str),
    Close(&'a str),
    Reopen(&'a str),
}

#[derive(Debug)]
struct Ticket {
    status: Status,
    owner: Option<String>,
}

fn main() {
    let events = vec![
        Event::Create("T1"),
        Event::Assign("T1", "alice"),
        Event::Start("T1"),
        Event::Close("T1"),
        Event::Reopen("T1"),
        Event::Start("T1"),
        Event::Close("T1"),
        Event::Create("T2"),
        Event::Start("T2"),
        Event::Assign("T2", "bob"),
        Event::Close("T2"),
        Event::Create("T3"),
        Event::Assign("T3", "carol"),
        Event::Assign("T3", "dave"),
        Event::Start("T3"),
        Event::Close("T3"),
        Event::Reopen("T3"),
        Event::Assign("T3", "erin"),
        Event::Close("T3"),
        Event::Create("T4"),
        Event::Close("T4"),
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();
    let mut invalid = 0;
    let mut valid_closed = 0;

    for event in events {
        match event {
            Event::Create(id) => {
                tickets.insert(
                    id,
                    Ticket {
                        status: Status::New,
                        owner: None,
                    },
                );
            }
            Event::Assign(id, owner) => {
                if let Some(ticket) = tickets.get_mut(id) {
                    ticket.owner = Some(owner.to_string());
                    ticket.status = Status::Assigned;
                } else {
                    invalid += 1;
                }
            }
            Event::Start(id) => {
                if let Some(ticket) = tickets.get_mut(id) {
                    match ticket.status {
                        Status::Assigned | Status::New => ticket.status = Status::InProgress,
                        _ => invalid += 1,
                    }
                } else {
                    invalid += 1;
                }
            }
            Event::Close(id) => {
                if let Some(ticket) = tickets.get_mut(id) {
                    ticket.status = Status::Closed;
                    valid_closed += 1;
                } else {
                    invalid += 1;
                }
            }
            Event::Reopen(id) => {
                if let Some(ticket) = tickets.get_mut(id) {
                    if ticket.status == Status::Closed {
                        ticket.status = Status::Assigned;
                    } else {
                        invalid += 1;
                    }
                } else {
                    invalid += 1;
                }
            }
        }
    }

    let mut new_count = 0;
    let mut assigned_count = 0;
    let mut in_progress_count = 0;
    let mut closed_count = 0;
    let mut owners = Vec::new();

    for (id, ticket) in &tickets {
        match ticket.status {
            Status::New => new_count += 1,
            Status::Assigned => assigned_count += 1,
            Status::InProgress => in_progress_count += 1,
            Status::Closed => closed_count += 1,
        }
        owners.push(format!(
            "{}={}",
            id,
            ticket.owner.as_deref().unwrap_or("unassigned")
        ));
    }

    println!(
        "new:{} assigned:{} in_progress:{} closed:{} invalid:{} valid_closed:{} owners:{}",
        new_count,
        assigned_count,
        in_progress_count,
        closed_count,
        invalid,
        valid_closed,
        owners.join(",")
    );
}

