struct Booking {
    room: &'static str,
    start: u8,
    end: u8,
}

fn has_conflict(existing: &[Booking], req: Booking) -> bool {
    existing.iter().any(|b| {
        b.room == req.room && req.start <= b.end && b.start <= req.end
    })
}

