#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Close,
    Reopen,
}

pub fn apply_events(events: &[Event]) -> Status {
    let mut status = Status::Open;

    for event in events {
        match (*event, status) {
            (Event::Start, Status::Open) => status = Status::InProgress,
            (Event::Close, Status::InProgress) => status = Status::Closed,
            (Event::Reopen, Status::Closed) => status = Status::Open,
            (Event::Close, Status::Open) => status = Status::Closed,
            _ => {}
        }
    }

    status
}

#[cfg(test)]
mod tests {
    use super::{apply_events, Event, Status};

    #[test]
    fn closes_after_work_starts() {
        let events = [Event::Start, Event::Close];
        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn can_reopen_a_closed_ticket() {
        let events = [Event::Start, Event::Close, Event::Reopen];
        assert_eq!(apply_events(&events), Status::Open);
    }

    #[test]
    fn reopened_ticket_can_be_closed_again_without_restart() {
        let events = [Event::Start, Event::Close, Event::Reopen, Event::Close];
        assert_eq!(apply_events(&events), Status::Closed);
    }
}

pub fn overlaps(a_start: u32, a_end: u32, b_start: u32, b_end: u32) -> bool {
    if a_start >= a_end || b_start >= b_end {
        return false;
    }

    a_start <= b_end && b_start <= a_end
}

pub fn can_book(existing: &[(u32, u32)], start: u32, end: u32) -> bool {
    if start >= end {
        return false;
    }

    !existing
        .iter()
        .any(|&(booked_start, booked_end)| overlaps(booked_start, booked_end, start, end))
}

#[cfg(test)]
mod tests {
    use super::{can_book, overlaps};

    #[test]
    fn adjacent_intervals_do_not_overlap() {
        assert!(!overlaps(10, 20, 20, 30));
        assert!(!overlaps(20, 30, 10, 20));
    }

    #[test]
    fn contained_intervals_do_overlap() {
        assert!(overlaps(10, 30, 15, 20));
        assert!(overlaps(15, 20, 10, 30));
    }

    #[test]
    fn booking_rejects_conflicts_but_allows_gaps() {
        let existing = [(10, 20), (30, 40)];
        assert!(!can_book(&existing, 15, 18));
        assert!(can_book(&existing, 20, 30));
        assert!(!can_book(&existing, 35, 45));
    }

    #[test]
    fn invalid_intervals_never_book() {
        let existing = [(5, 10)];
        assert!(!can_book(&existing, 8, 8));
        assert!(!can_book(&existing, 9, 7));
        assert!(!overlaps(4, 4, 4, 5));
    }
}

