#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub points_for: u32,
    pub points_against: u32,
}

impl Player {
    fn match_points(&self) -> u32 {
        self.wins * 3 + self.draws
    }

    fn point_diff(&self) -> i32 {
        self.points_for as i32 - self.points_against as i32
    }
}

pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut rows = players.to_vec();
    rows.sort_by(|a, b| {
        b.match_points()
            .cmp(&a.match_points())
            .then_with(|| b.wins.cmp(&a.wins))
            .then_with(|| b.points_for.cmp(&a.points_for))
            .then_with(|| a.name.cmp(b.name))
    });

    rows.into_iter()
        .map(|p| format!("{}:{}", p.name, p.match_points()))
        .collect()
}

#[cfg(test)]
mod tests {
