    #[test]
    fn ranks_by_points_then_diff_then_points_for_then_name() {
        let players = vec![
            Player { name: "Zed", wins: 4, draws: 0, points_for: 80, points_against: 70 },
            Player { name: "Amy", wins: 3, draws: 3, points_for: 90, points_against: 60 },
            Player { name: "Bob", wins: 3, draws: 3, points_for: 85, points_against: 55 },
            Player { name: "Cal", wins: 3, draws: 3, points_for: 88, points_against: 58 },
        ];

        let got = leaderboard(&players);
        let want = vec!["Bob:12", "Cal:12", "Amy:12", "Zed:12"];
