use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale {
    pub region: &'static str,
    pub amount: i32,
    pub refunded: bool,
}

pub fn summarize(sales: &[Sale]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();
    let mut counts: BTreeMap<&str, usize> = BTreeMap::new();

    for sale in sales {
        *totals.entry(sale.region).or_insert(0) += sale.amount;
        *counts.entry(sale.region).or_insert(0) += 1;
    }

    let mut out = Vec::new();
    for (region, total) in totals {
        let count = counts.get(region).copied().unwrap_or(0);
        out.push(format!("{}: total={}, orders={}", region, total, count));
    }

    if out.is_empty() {
        "no sales".to_string()
    } else {
        out.join("\n")
    }
}

#[cfg(test)]
