    use super::*;

    #[test]
    fn groups_regions_and_ignores_refunds_in_totals() {
        let sales = [
            Sale { region: "east", amount: 40, refunded: false },
            Sale { region: "west", amount: 15, refunded: true },
            Sale { region: "east", amount: 10, refunded: true },
            Sale { region: "west", amount: 35, refunded: false },
        ];

        let report = summarize(&sales);
        assert_eq!(report, "east: total=40, orders=1\nwest: total=35, orders=1");
