#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Command {
    Start,
    Stop,
    Pause,
    Resume,
}

pub fn apply(currently_running: bool, cmd: Command) -> &'static str {
    match cmd {
        Command::Start => {
            if currently_running {
                "already running"
            } else {
                "started"
            }
        }
        Command::Stop => {
            if currently_running {
                "stopped"
            } else {
                "already stopped"
            }
        }
        Command::Pause => {
            if currently_running {
                "paused"
            } else {
                "already stopped"
            }
        }
        Command::Resume => "started",
    }
}

#[cfg(test)]
mod tests {
    use super::{apply, Command};

    #[test]
    fn start_and_stop_respect_state() {
        assert_eq!(apply(false, Command::Start), "started");
        assert_eq!(apply(true, Command::Start), "already running");
        assert_eq!(apply(true, Command::Stop), "stopped");
        assert_eq!(apply(false, Command::Stop), "already stopped");
    }

    #[test]
    fn pause_requires_running() {
        assert_eq!(apply(true, Command::Pause), "paused");
        assert_eq!(apply(false, Command::Pause), "already stopped");
    }

    #[test]
    fn resume_has_distinct_behavior() {
        assert_eq!(apply(false, Command::Resume), "resumed");
        assert_eq!(apply(true, Command::Resume), "already running");
    }
}

