        let existing = [b(10, 20), b(30, 40)];
        assert!(can_book(&existing, b(20, 30)));
        assert_eq!(first_conflict(&existing, b(20, 30)), None);
    }

    #[test]
    fn contained_and_partial_overlaps_conflict() {
        let existing = [b(10, 20), b(30, 40)];
        assert!(!can_book(&existing, b(12, 18)));
        assert_eq!(first_conflict(&existing, b(12, 18)), Some(b(10, 20)));
        assert!(!can_book(&existing, b(18, 22)));
